class FoxController{constructor(elementId){this.element=document.getElementById(elementId);this.animations={idle:{frames:14,sheet:'idle-sheet.png',frameRate:125},movement:{frames:7,sheet:'movement-sheet.png',frameRate:125},sleep:{frames:6,sheet:'sleep-sheet.png',frameRate:250}};this.currentState='idle';this.nextState='idle';this.currentFrame=1;this.animationTimer=null;this.clientX=0;this.clientY=0;this.worldX=0;this.worldY=0;this.isDetached=!1;this.initialized=!1;this.isTouchDevice=window.matchMedia("(pointer: coarse)").matches;const savedPref=localStorage.getItem('foxTracking');this.isTrackingEnabled=this.isTouchDevice?!1:(savedPref===null?!0:savedPref==='true');this.placeholder=null;this.isReturning=!1;this.idleTimeout=null;this.isSleeping=!1;this.speed=3;this.isTracking=!1;this.facingRight=!0;if(this.element){this.element.style.transition='none';this.element.style.objectFit='cover';Object.values(this.animations).forEach(anim=>{const img=new Image();img.onload=()=>{anim.frameAspect=(img.naturalWidth/anim.frames)/img.naturalHeight};img.src=`/assets/char/${anim.sheet}`});const initialSheet=`/assets/char/${this.animations[this.currentState].sheet}`;const handleLoad=()=>{let frameAspect=this.animations[this.currentState].frameAspect;if(!frameAspect){const sheetWidth=this.element.naturalWidth;const sheetHeight=this.element.naturalHeight;if(sheetWidth&&sheetHeight){frameAspect=(sheetWidth/this.animations[this.currentState].frames)/sheetHeight}else{frameAspect=1}}
this.element.style.width=`${this.element.clientHeight * frameAspect}px`;this.initLayout()};if(this.element.src.includes(initialSheet)&&this.element.complete){handleLoad()}else{this.element.addEventListener('load',handleLoad,{once:!0});this.element.src=initialSheet}}}
setState(newState){if(this.animations[newState]){this.nextState=newState}else{console.warn(`FoxController: State '${newState}' is not defined.`)}}
initLayout(){if(this.initialized)return;this.initialized=!0;this.element.onload=null;this.setupToggle();this.startAnimation();this.initTracking()}
setupToggle(){const toggle=document.getElementById('fox-toggle');if(toggle){if(this.isTouchDevice)return;toggle.checked=this.isTrackingEnabled;toggle.addEventListener('change',(e)=>{this.isTrackingEnabled=e.target.checked;localStorage.setItem('foxTracking',this.isTrackingEnabled);if(!this.isTrackingEnabled){this.isSleeping=!1;clearTimeout(this.idleTimeout)}else{this.resetIdleTimer()}})}}
detachFromLayout(){if(this.isDetached)return;const rect=this.element.getBoundingClientRect();this.placeholder=document.createElement('div');this.placeholder.style.width=rect.width+'px';this.placeholder.style.height=rect.height+'px';this.element.parentNode.insertBefore(this.placeholder,this.element);document.body.appendChild(this.element);this.element.style.position='absolute';this.element.style.left='0px';this.element.style.top='0px';this.element.style.zIndex='9999';this.worldX=rect.left+window.scrollX+(rect.width/2);this.worldY=rect.top+window.scrollY+(rect.height/2);this.isDetached=!0}
attachToLayout(){if(!this.isDetached||!this.placeholder)return;this.placeholder.parentNode.insertBefore(this.element,this.placeholder);this.placeholder.remove();this.placeholder=null;this.element.style.position='';this.element.style.left='';this.element.style.top='';this.element.style.zIndex='';this.element.style.transform=`scaleX(${this.facingRight ? 1 : -1})`;this.isDetached=!1;this.isReturning=!1;this.setState('idle')}
initTracking(){if(this.isTouchDevice)return;document.addEventListener('mousemove',(e)=>{this.clientX=e.clientX;this.clientY=e.clientY;this.isTracking=!0;if(this.isSleeping){this.isSleeping=!1;this.setState('idle')}
this.resetIdleTimer()});this.resetIdleTimer();requestAnimationFrame(()=>this.updatePosition())}
resetIdleTimer(){clearTimeout(this.idleTimeout);if(!this.isTrackingEnabled)return;this.idleTimeout=setTimeout(()=>{if(this.isDetached&&!this.isReturning){this.isSleeping=!0;this.setState('sleep')}},30000)}
updatePosition(){if(!this.isTrackingEnabled&&!this.isDetached){requestAnimationFrame(()=>this.updatePosition());return}
if(this.isTrackingEnabled&&!this.isTracking){requestAnimationFrame(()=>this.updatePosition());return}
let targetX,targetY;let stopDistance=(this.element.clientWidth/2)+10;if(this.isTrackingEnabled){this.isReturning=!1;if(!this.isDetached)this.detachFromLayout();targetX=this.clientX+window.scrollX;targetY=this.clientY+window.scrollY}else if(this.placeholder){this.isReturning=!0;const pRect=this.placeholder.getBoundingClientRect();targetX=pRect.left+window.scrollX+(pRect.width/2);targetY=pRect.top+window.scrollY+(pRect.height/2);stopDistance=2}
const dx=targetX-this.worldX;const dy=targetY-this.worldY;const distance=Math.sqrt(dx*dx+dy*dy);if(distance>stopDistance){this.setState('movement')}else{if(this.isReturning){this.attachToLayout();requestAnimationFrame(()=>this.updatePosition());return}else if(this.isSleeping){this.setState('sleep')}else{this.setState('idle')}}
if(this.currentState==='movement'&&distance>stopDistance){const nx=dx/distance;const ny=dy/distance;this.worldX+=nx*this.speed;this.worldY+=ny*this.speed;if(dx>1){this.facingRight=!0}else if(dx<-1){this.facingRight=!1}}
if(this.isDetached){const drawX=this.worldX-(this.element.clientWidth/2);const drawY=this.worldY-(this.element.clientHeight/2);const scaleX=this.facingRight?1:-1;this.element.style.transform=`translate(${drawX}px, ${drawY}px) scaleX(${scaleX})`}
requestAnimationFrame(()=>this.updatePosition())}
startAnimation(){this.stopAnimation();const currentSpeed=this.animations[this.currentState].frameRate;this.animationTimer=setInterval(()=>this.updateFrame(),currentSpeed)}
stopAnimation(){if(this.animationTimer)clearInterval(this.animationTimer);}
updateFrame(){this.currentFrame++;if(this.currentFrame>this.animations[this.currentState].frames){this.currentFrame=1;if(this.currentState!==this.nextState){this.currentState=this.nextState;this.element.src=`/assets/char/${this.animations[this.currentState].sheet}`;if(this.animations[this.currentState].frameAspect){this.element.style.width=`${this.element.clientHeight * this.animations[this.currentState].frameAspect}px`}
this.startAnimation()}}
const totalFrames=this.animations[this.currentState].frames;const positionPercent=totalFrames>1?((this.currentFrame-1)/(totalFrames-1))*100:0;this.element.style.objectPosition=`${positionPercent}% 0`}}
document.addEventListener('DOMContentLoaded',()=>{window.foxCompanion=new FoxController('fox-character')})